code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

rl.question('', (t) => {
    let testCasesRemaining = parseInt(t);

    const handleTestCase = () => {
        if (testCasesRemaining > 0) {
            rl.question('', (input) => {
                const [n, m, x] = input.split(' ').map(Number);
                console.log(2 * x * (n + m));
                testCasesRemaining--;
                handleTestCase();
            });
        } else {
            rl.close();
        }
    };

    handleTestCase();
});

